# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy database simulation
users = {
    'user1': {'email': 'user1@example.com', 'password': 'pass123', 'two_factor_enabled': False}
}

@app.route('/update_profile', methods=['POST'])
def update_profile():
    if 'username' not in session:
        return jsonify({'error': 'User not logged in'}), 401

    username = session['username']
    user = users.get(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    data = request.json
    new_email = data.get('email')
    new_password = data.get('password')
    two_factor_enabled = data.get('two_factor_enabled')

    if new_email:
        user['email'] = new_email
    if new_password:
        user['password'] = new_password
    if two_factor_enabled is not None:
        user['two_factor_enabled'] = two_factor_enabled

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)